import * as tasks from "@/repos/tasks";

export async function GET(request, { params }) {
  try {
    const { id } = await params;
    const data = await tasks.get(id);
    if (!data) return Response.json({ error: "Task not found" }, { status: 404 });
    return Response.json(data);
  } catch (e) {
    return Response.json({ error: e.message }, { status: 500 });
  }
}

export async function PATCH(request, { params }) {
  try {
    const { id } = await params;
    const body = await request.json();
    return Response.json(await tasks.set(id, body));
  } catch (e) {
    return Response.json({ error: e.message }, { status: 400 });
  }
}

export async function DELETE(request, { params }) {
  try {
    const { id } = await params;
    return Response.json(await tasks.remove(id));
  } catch (e) {
    return Response.json({ error: e.message }, { status: 500 });
  }
}